<script>
(function() {
    // --- WebGL Setup ---
    const canvas = document.getElementById('coin-hero');
    const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');

    if (!gl) {
        alert("WebGL not supported");
        return;
    }

    // Resize handling
    function resize() {
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        gl.viewport(0, 0, canvas.width, canvas.height);
    }
    resize();
    window.addEventListener('resize', resize);

    // --- Shaders ---
    const vsSource = `
        attribute vec3 aPosition;
        attribute vec2 aUV;
        attribute vec3 aNormal;

        uniform mat4 uModelViewMatrix;
        uniform mat4 uProjectionMatrix;

        varying vec2 vUV;
        varying vec3 vNormal;
        varying vec3 vPos;

        void main() {
            gl_Position = uProjectionMatrix * uModelViewMatrix * vec4(aPosition, 1.0);
            vUV = aUV;
            // Transform normal by modelview matrix (ignoring scale for simplicity)
            vNormal = mat3(uModelViewMatrix) * aNormal;
            vPos = vec3(uModelViewMatrix * vec4(aPosition, 1.0));
        }
    `;

    const fsSource = `
        precision mediump float;

        uniform sampler2D uTextureFront;
        uniform sampler2D uTextureBack;
        uniform sampler2D uTextureSide;

        varying vec2 vUV;
        varying vec3 vNormal;
        varying vec3 vPos;

        void main() {
            // Determine face based on normal Z component (approx) or UV logic.
            // Simplified: Use a mix of textures based on world space position relative to center?
            // Better: Pass a 'faceID' attribute, but we are drawing separate meshes for faces in JS.

            vec3 color = texture2D(uTextureFront, vUV).rgb;

            // Lighting
            vec3 lightDir = normalize(vec3(1.0, 1.0, 1.0));
            vec3 viewDir = normalize(-vPos);
            float NdotL = max(dot(normalize(vNormal), lightDir), 0.0);

            // Specular (Phong)
            vec3 reflectDir = reflect(-lightDir, normalize(vNormal));
            float spec = pow(max(dot(viewDir, reflectDir), 0.0), 32.0);

            // Ambient
            vec3 ambient = vec3(0.15);

            gl_FragColor = vec4(color * (NdotL + ambient) + vec3(spec * 0.8), 1.0);
        }
    `;

    function createShader(gl, type, source) {
        const shader = gl.createShader(type);
        gl.shaderSource(shader, source);
        gl.compileShader(shader);
        if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
            console.error('Shader compile error:', gl.getShaderInfoLog(shader));
            gl.deleteShader(shader);
            return null;
        }
        return shader;
    }

    const program = createProgram(gl, vsSource, fsSource);

    function createProgram(gl, vs, fs) {
        const v = createShader(gl, gl.VERTEX_SHADER, vs);
        const f = createShader(gl, gl.FRAGMENT_SHADER, fs);
        const p = gl.createProgram();
        gl.attachShader(p, v);
        gl.attachShader(p, f);
        gl.linkProgram(p);
        if (!gl.getProgramParameter(p, gl.LINK_STATUS)) {
            console.error('Program link error:', gl.getProgramInfoLog(p));
            return null;
        }
        return p;
    }

    // --- Texture Generation (Procedural) ---
    function createTexture(ctx, width, height, drawFn) {
        const c = document.createElement('canvas');
        c.width = width;
        c.height = height;
        const cx = c.getContext('2d');
        drawFn(cx, width, height);

        const tex = gl.createTexture();
        gl.bindTexture(gl.TEXTURE_2D, tex);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.REPEAT); // Side repeats
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);

        // Front/Back don't repeat usually, but for simplicity we use CLAMP.
        if (width === 512 && height === 512) {
             gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
             gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
        }

        gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, c);

        // Hide the canvas
        c.style.display = 'none';
        document.body.appendChild(c);
        return tex;
    }

    // Generate Front Texture (Emblem)
    const frontTex = createTexture(gl, 512, 512, (ctx, w, h) => {
        const grad = ctx.createRadialGradient(w/2, h/2, 0, w/2, h/2, w);
        grad.addColorStop(0, '#fff');
        grad.addColorStop(1, '#b8860b'); // DarkGoldenRod

        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, w, h);

        // Emblem Shape (W)
        ctx.save();
        ctx.translate(w/2, h/2);
        ctx.scale(1.5, 1.5);

        const embossColor = '#8B6914';
        const highlight = '#FFD700';

        // Draw W shape with shadow for relief
        ctx.beginPath();
        ctx.moveTo(-100, -50);
        ctx.lineTo(-60, 50);
        ctx.lineTo(0, -20);
        ctx.lineTo(60, 50);
        ctx.lineTo(100, -50);
        ctx.strokeStyle = embossColor;
        ctx.lineWidth = 40;
        ctx.lineCap = 'round';
        ctx.stroke();

        // Inner Highlight (Simulate raised edge)
        ctx.beginPath();
        ctx.moveTo(-100, -50);
        ctx.lineTo(-60, 50);
        ctx.lineTo(0, -20);
        ctx.lineTo(60, 50);
        ctx.lineTo(100, -50);
        ctx.strokeStyle = highlight;
        ctx.lineWidth = 8;
        ctx.lineCap = 'round';
        ctx.stroke();

        // Text "WastedToken" below
        ctx.font = 'bold 40px sans-serif';
        ctx.fillStyle = embossColor;
        ctx.textAlign = 'center';
        ctx.fillText('WASTEDTOKEN', 0, 120);

        ctx.restore();
    });

    // Generate Back Texture (Denomination)
    const backTex = createTexture(gl, 512, 512, (ctx, w, h) => {
        const grad = ctx.createRadialGradient(w/2, h/2, 0, w/2, h/2, w);
        grad.addColorStop(0, '#fff');
        grad.addColorStop(1, '#708090'); // SlateGray

        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, w, h);

        const textGrad = ctx.createLinearGradient(0, 0, 0, h);
        textGrad.addColorStop(0, '#fff');
        textGrad.addColorStop(1, '#aaa');

        ctx.font = 'bold 80px sans-serif';
        ctx.fillStyle = textGrad;
        ctx.textAlign = 'center';
        ctx.fillText('10,000', w/2, h/2 - 20);

        ctx.font = '40px sans-serif';
        ctx.fillStyle = '#888';
        ctx.fillText('TOKENS', w/2, h/2 + 50);

        // Border ring
        ctx.beginPath();
        ctx.arc(w/2, h/2, 180, 0, Math.PI*2);
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 10;
        ctx.stroke();
    });

    // Generate Side Texture (Reeded)
    const sideTex = createTexture(gl, 512, 256, (ctx, w, h) => {
        // Vertical stripes to simulate reeding
        for(let i=0; i<w; i+=4) {
            ctx.fillStyle = '#b8860b';
            ctx.fillRect(i, 0, 3, h);
            ctx.fillStyle = '#d4af37';
            ctx.fillRect(i+4, 0, 2, h);
        }
    });

    // --- Geometry & Buffers ---

    // Helper to create a disk (Front/Back)
    function createDisk(radius, segments) {
        const positions = [];
        const normals = [];
        const uvs = [];

        for(let i=0; i<=segments; i++) {
            const theta = (i / segments) * Math.PI * 2;
            const x = Math.cos(theta) * radius;
            const y = Math.sin(theta) * radius;

            // Outer ring vertices
            positions.push(x, y, -0.05); // Front face z
            normals.push(0, 0, -1);
            uvs.push((x/radius + 1)/2, (y/radius + 1)/2);

            // Inner center vertex for fan? No, let's do rings for better UVs.
        }

        // Simpler: Triangle Fan from center to outer ring
        const verts = [];
        const norms = [];
        const uvsMap = [];

        verts.push(0, 0, -0.05);
        norms.push(0, 0, -1);
        uvsMap.push(0.5, 0.5);

        for(let i=0; i<=segments; i++) {
            const theta = (i / segments) * Math.PI * 2;
            const x = Math.cos(theta) * radius;
            const y = Math.sin(theta) * radius;

            verts.push(x, y, -0.05);
            norms.push(0, 0, -1);
            uvsMap.push((x/radius + 1)/2, (y/radius + 1)/2);
        }

        // Indices for triangle fan
        const indices = [];
        for(let i=1; i<verts.length/3-1; i++) {
            indices.push(0, i, i+1);
        }

        return { verts: new Float32Array(verts), norms: new Float32Array(norms), uvs: new Float32Array(uvsMap), indices: new Uint16Array(indices) };
    }

    // Helper to create Side Walls (Cylinder)
    function createSide(radius, thickness, segments) {
        const verts = [];
        const norms = [];
        const uvs = [];

        for(let i=0; i<=segments; i++) {
            const theta = (i / segments) * Math.PI * 2;
            const x = Math.cos(theta) * radius;
            const y = Math.sin(theta) * radius;

            // Top vertex
            verts.push(x, y, -thickness/2);
            norms.push(Math.cos(theta), Math.sin(theta), 0);
            uvs.push(i/segments, 0);

            // Bottom vertex
            verts.push(x, y, thickness/2);
            norms.push(Math.cos(theta), Math.sin(theta), 0);
            uvs.push(i/segments, 1);
        }

        const indices = [];
        for(let i=0; i<verts.length/6-1; i++) {
            // Two triangles per segment strip
            const a = i*2;
            const b = i*2 + 1;
            const c = (i+1)*2;
            const d = (i+1)*2 + 1;

            indices.push(a, b, c);
            indices.push(b, d, c);
        }

        return { verts: new Float32Array(verts), norms: new Float32Array(norms), uvs: new Float32Array(uvs), indices: new Uint16Array(indices) };
    }

    const disk = createDisk(0.5, 64);
    const side = createSide(0.5, 0.1, 64); // Thickness 0.1

    // --- Buffers ---
    function createBuffer(data, type) {
        const buf = gl.createBuffer();
        gl.bindBuffer(type, buf);
        gl.bufferData(type, data, gl.STATIC_DRAW);
        return buf;
    }

    const vboPos = createBuffer(disk.verts, gl.ARRAY_BUFFER);
    const vboNorm = createBuffer(disk.norms, gl.ARRAY_BUFFER);
    const vboUV = createBuffer(disk.uvs, gl.ARRAY_BUFFER);

    const ibo = createBuffer(disk.indices, gl.ELEMENT_ARRAY_BUFFER);

    // Side Buffers (Separate for different texture)
    const sVboPos = createBuffer(side.verts, gl.ARRAY_BUFFER);
    const sVboNorm = createBuffer(side.norms, gl.ARRAY_BUFFER);
    const sVboUV = createBuffer(side.uvs, gl.ARRAY_BUFFER);
    const sIbo = createBuffer(side.indices, gl.ELEMENT_ARRAY_BUFFER);

    // --- Attributes & Uniforms ---
    const aPosLoc = gl.getAttribLocation(program, 'aPosition');
    const aNormLoc = gl.getAttribLocation(program, 'aNormal');
    const aUVLoc = gl.getAttribLocation(program, 'aUV');

    const uMVP = gl.getUniformLocation(program, 'uProjectionMatrix');
    const uMV = gl.getUniformLocation(program, 'uModelViewMatrix');
    const uTexFront = gl.getUniformLocation(program, 'uTextureFront');
    const uTexBack = gl.getUniformLocation(program, 'uTextureBack');
    const uTexSide = gl.getUniformLocation(program, 'uTextureSide');

    // --- Matrices ---
    function perspective(fov, aspect, near, far) {
        const f = 1.0 / Math.tan(fov / 2);
        const nf = 1 / (near - far);
        return [
            f / aspect, 0, 0, 0,
            0, f, 0, 0,
            0, 0, (far + near) * nf, -1,
            0, 0, (2 * far * near) * nf, 0
        ];
    }

    function lookAt(eye, center, up) {
        // Simple lookAt implementation
        const z = normalize(subtract(eye, center));
        const x = normalize(cross(up, z));
        const y = cross(z, x);

        return [
            x[0], y[0], z[0], 0,
            x[1], y[1], z[1], 0,
            x[2], y[2], z[2], 0,
            -dot(x, eye), -dot(y, eye), -dot(z, eye), 1
        ];
    }

    function multiply(a, b) {
        const out = new Float32Array(16);
        for(let i=0; i<4; i++) {
            for(let j=0; j<4; j++) {
                let sum = 0;
                for(let k=0; k<4; k++) sum += a[i*4+k] * b[k*4+j];
                out[i*4+j] = sum;
            }
        }
        return out;
    }

    function normalize(v) {
        const len = Math.sqrt(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]);
        return [v[0]/len, v[1]/len, v[2]/len];
    }

    function subtract(a, b) { return [a[0]-b[0], a[1]-b[1], a[2]-b[2]]; }
    function cross(a, b) { 
        return [a[1]*b[2] - a[2]*b[1], a[2]*b[0] - a[0]*b[2], a[0]*b[1] - a[1]*b[0]]; 
    }
    function dot(a, b) { return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]; }

    // --- Animation State ---
    let isPaused = false;
    let animationId;
    const startTime = Date.now();

    function draw() {
        if (isPaused) return;

        // Update time based on loop duration (e.g., 10 seconds per cycle)
        const now = Date.now();
        const elapsed = (now - startTime) / 1000;
        const t = elapsed % 10.0 / 10.0; // Loop 0-1

        render(t);
        animationId = requestAnimationFrame(draw);
    }

    function render(time) {
        gl.useProgram(program);

        // Clear
        gl.clearColor(0.05, 0.05, 0.08, 1.0);
        gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
        gl.enable(gl.DEPTH_TEST);

        // Camera
        const aspect = canvas.width / canvas.height;
        const proj = perspective(Math.PI/4, aspect, 0.1, 100.0);

        // View Matrix (Camera at z=3 looking at origin)
        const view = lookAt([0, 0, 3], [0, 0, 0], [0, 1, 0]);

        // Model Matrix: Rotate Y and Flip X based on time
        const angleY = time * Math.PI * 2; // Full spin
        const angleX = time * Math.PI;     // Full flip (end over end)

        const cosY = Math.cos(angleY);
        const sinY = Math.sin(angleY);
        const cosX = Math.cos(angleX);
        const sinX = Math.sin(angleX);

        // Rotation Y
        const rotY = [
            cosY, 0, -sinY, 0,
            0, 1, 0, 0,
            sinY, 0, cosY, 0,
            0, 0, 0, 1
        ];

        // Rotation X (Flip)
        const rotX = [
            1, 0, 0, 0,
            0, cosX, sinX, 0,
            0, -sinX, cosX, 0,
            0, 0, 0, 1
        ];

        const model = multiply(rotY, rotX); // Order matters: Y then X

        const mvp = multiply(proj, multiply(view, model));

        gl.uniformMatrix4fv(uMVP, false, new Float32Array(mvp));
        gl.uniformMatrix4fv(uMV, false, new Float32Array(model));

        // --- Draw Front Face (Texture 1) ---
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, frontTex);
        gl.uniform1i(uTexFront, 0);

        gl.bindBuffer(gl.ARRAY_BUFFER, vboPos);
        gl.vertexAttribPointer(aPosLoc, 3, gl.FLOAT, false, 0, 0);
        gl.enableVertexAttribArray(aPosLoc);

        gl.bindBuffer(gl.ARRAY_BUFFER, vboNorm);
        gl.vertexAttribPointer(aNormLoc, 3, gl.FLOAT, false, 0, 0);
        gl.enableVertexAttribArray(aNormLoc);

        gl.bindBuffer(gl.ARRAY_BUFFER, vboUV);
        gl.vertexAttribPointer(aUVLoc, 2, gl.FLOAT, false, 0, 0);
        gl.enableVertexAttribArray(aUVLoc);

        gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, ibo);
        gl.drawElements(gl.TRIANGLES, disk.indices.length, gl.UNSIGNED_SHORT, 0);

        // --- Draw Back Face (Texture 2) ---
        // Reuse geometry but flip normals? Or just draw with different texture.
        // We need to swap the buffer for back face vertices if we want correct orientation or just use same mesh and let lighting handle it.
        // For simplicity, re-bind front buffer but change texture.

        gl.activeTexture(gl.TEXTURE1);
        gl.bindTexture(gl.TEXTURE_2D, backTex);
        gl.uniform1i(uTexBack, 1);

        // Note: The shader currently only samples uTextureFront. 
        // To support multiple textures in one pass without complex logic, we need to switch programs or use texture units and conditional sampling.
        // Given the constraints of a single file and simplicity, I will draw Front, then Back (with different program state).

        // Switch shader to sample from uTexBack? 
        // To keep it simple in one pass: We can't easily mix textures without changing shaders or using complex UVs.
        // Let's change the approach: Draw Front with Program A, Draw Back with Program B (or same program but different uniform).
        // Actually, I'll modify the shader to accept a 'uTextureID' and sample accordingly? No, that requires texture units in fragment.

        // SIMPLIFICATION: Since we are drawing separate meshes (Front/Back/Side), we can just change the active texture unit and update the uniform before draw call.
        // But the shader needs to know WHICH texture to use.
        // Let's modify the Fragment Shader to sample from a specific unit based on an attribute or uniform? 
        // Better: Use 3 separate draw calls with different textures, but the shader must be updated to look at the correct uniform.

        // To avoid complex shader changes, I will create a second program that samples uTexBack? No, same code logic.
        // Let's use one program and pass texture coordinates that map to specific faces? 
        // EASIEST: Draw Front with Texture 0 bound to uTexFront. Then Draw Back with Texture 1 bound to uTexFront (overwriting uniform).

        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, backTex);
        gl.uniform1i(uTexFront, 0); // Reuse Front Uniform for Back texture

        // We need to draw the BACK face vertices. 
        // The disk buffer is front-facing (normals -z). For back face we want normals +z?
        // Actually, if I use the same geometry but flip it in model matrix or just draw it with different normals.
        // Let's create a separate buffer for Back Face that has flipped normals and reversed UVs if needed.

        // To keep code size low: I will reuse the disk vertices but modify the Model Matrix to flip Z? 
        // No, let's just use the same geometry but draw it with different attributes (normals).
        // Since we can't easily swap buffers without complexity, I'll create a second set of buffers for Back Face in JS.

        // --- DRAW BACK FACE ---
        const backVerts = disk.verts.map((v, i) => i%3===2 ? -v : v); // Flip Z? No, just flip normals.
        // Actually, simpler: The Front face is at z=-0.05. Back face should be at z=+0.05 (or -0.05 with flipped normal).
        // Let's create a specific buffer for Back Face in the setup phase to ensure correctness.

        // Since I already wrote `createDisk`, let's assume we have a `backBuffer` ready? 
        // No, I'll just modify the disk vertices for back face: z = +0.05, normal = (0,0,1).
    }

    // --- Revised Geometry Setup for Back Face ---
    const backDisk = createDisk(0.5, 64);
