        const grad = ctx.createRadialGradient(w/2, h/2, 0, w/2, h/2, w);
        if(colorType === 'bronze') {
            grad.addColorStop(0, '#e6c87a');
            grad.addColorStop(1, '#cd7f32');
        } else if (colorType === 'silver') {
